import { Request, Response, NextFunction } from 'express';
import { prisma } from '../../lib/prisma';
import { z } from 'zod';

const searchClientsQuery = z.object({ q: z.string().min(1) });

export async function searchClients(req: Request, res: Response, next: NextFunction) {
  try {
    const parsed = searchClientsQuery.parse(req.query);
    const q = parsed.q;
    const clients = await prisma.client.findMany({
      where: {
        tenantId: req.tenantId,
        name: { contains: q, mode: 'insensitive' },
      },
    });
    if (clients) {
      return res.json(clients);
    } else {
      return res.json([]);
    }
  } catch (err) {
    return next(err);
  }
}

export async function deleteClient(req: Request, res: Response, next: NextFunction) {
  const { id } = req.params;
  try {
    await prisma.client.delete({ where: { id, tenantId: req.tenantId } });
    res.status(204).send();
  } catch (err) {
    next(err);
  }
}
```
