func (s *DeliveryService) CancelDelivery(ctx context.Context, deliveryID string, reason string) error {
	var delivery models.Delivery
	if err := s.db.WithContext(ctx).First(&delivery, "id = ?", deliveryID).Error; err != nil {
		return err
	}
	if delivery.Status == "COMPLETED" {
		return fmt.Errorf("cannot cancel completed delivery")
	}
	delivery.Status = "CANCELLED"
	delivery.CancelReason = reason
	delivery.CancelledAt = time.Now()
	if err := s.db.WithContext(ctx).Save(&delivery).Error; err != nil {
		return err
	}
	return nil
}
